namespace sv_d4f52afe12f64f4eab6541c86f46a356.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_d4f52afe12f64f4eab6541c86f46a356.Components.Pages.Settings

<nav class="settings-sidebar" role="tablist" aria-label="Settings sections">
    @foreach (var section in Sections)
    {
        <button class="sidebar-item @(ActiveSection == section.Key ? "active" : "")"
                role="tab"
                aria-selected="@(ActiveSection == section.Key)"
                @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
            <span class="sidebar-icon">@section.Icon</span>
            <span class="sidebar-label">@section.Label</span>
        </button>
    }
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];
}

.settings-sidebar {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    padding: 1rem;
    min-width: 200px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    height: 100%;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1rem;
    border: none;
    border-radius: 0.5rem;
    background: transparent;
    color: #495057;
    font-size: 0.95rem;
    cursor: pointer;
    transition: all 0.15s ease;
    text-align: left;
}

.sidebar-item:hover {
    background: #e9ecef;
    color: #212529;
}

.sidebar-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

@namespace sv_d4f52afe12f64f4eab6541c86f46a356.Components.Pages.Settings
@using sv_d4f52afe12f64f4eab6541c86f46a356.Models

@if (Session is not null)
{
    <div class="dialog-backdrop" @onclick="OnCancel.InvokeAsync">
        <div class="dialog-content" @onclick:stopPropagation="true">
            <h5>Revoke Session</h5>
            <p>
                Are you sure you want to revoke the session on
                <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?
            </p>
            <p class="text-muted">This will immediately sign out that device.</p>
            <div class="dialog-actions">
                <button class="btn btn-secondary" @onclick="OnCancel.InvokeAsync" disabled="@IsRevoking">Cancel</button>
                <button class="btn btn-danger" @onclick="OnConfirm.InvokeAsync" disabled="@IsRevoking">
                    @if (IsRevoking)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Revoke
                </button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public ActiveSession? Session { get; set; }

    [Parameter]
    public bool IsRevoking { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnConfirm { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancel { get; set; }
}

.dialog-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.dialog-content {
    background: #fff;
    border-radius: 0.75rem;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
}

.dialog-content h5 {
    margin-bottom: 1rem;
}

.dialog-actions {
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
    margin-top: 1.5rem;
}

@namespace sv_d4f52afe12f64f4eab6541c86f46a356.Components.Pages.Settings
@using sv_d4f52afe12f64f4eab6541c86f46a356.Models

<div class="sessions-section">
    <h6>Active Sessions</h6>
    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions found.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession> Sessions { get; set; } = [];

    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<ActiveSession> OnRevokeRequested { get; set; }
}

@namespace sv_d4f52afe12f64f4eab6541c86f46a356.Components.Pages.Settings
@using sv_d4f52afe12f64f4eab6541c86f46a356.Models

<div class="password-panel">
    <button class="panel-toggle" @onclick="ToggleExpanded">
        <span>🔑 Change Password</span>
        <span class="toggle-icon">@(IsExpanded ? "▲" : "▼")</span>
    </button>

    @if (IsExpanded)
    {
        <div class="panel-body">
            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="HandleUpdatePassword" disabled="@_isSaving">
                @if (_isSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    private bool IsExpanded { get; set; }
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _message;
    private bool _isError;
    private bool _isSaving;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task HandleUpdatePassword()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _message = "Current password is required.";
            _isError = true;
            return;
        }

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "New password is required.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _isSaving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _message = "Password updated successfully.";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _isSaving = false;
        }
    }
}

.password-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
}

.panel-toggle {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.875rem 1rem;
    border: none;
    background: #f8f9fa;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s;
}

.panel-toggle:hover {
    background: #e9ecef;
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

