@namespace sv_d4f52afe12f64f4eab6541c86f46a356.Components.Pages.Settings
@using sv_d4f52afe12f64f4eab6541c86f46a356.Models

@if (Session is not null)
{
    <div class="dialog-backdrop" @onclick="OnCancel.InvokeAsync">
        <div class="dialog-content" @onclick:stopPropagation="true">
            <h5>Revoke Session</h5>
            <p>
                Are you sure you want to revoke the session on
                <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?
            </p>
            <p class="text-muted">This will immediately sign out that device.</p>
            <div class="dialog-actions">
                <button class="btn btn-secondary" @onclick="OnCancel.InvokeAsync" disabled="@IsRevoking">Cancel</button>
                <button class="btn btn-danger" @onclick="OnConfirm.InvokeAsync" disabled="@IsRevoking">
                    @if (IsRevoking)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Revoke
                </button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public ActiveSession? Session { get; set; }

    [Parameter]
    public bool IsRevoking { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnConfirm { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancel { get; set; }
}

.dialog-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.dialog-content {
    background: #fff;
    border-radius: 0.75rem;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
}

.dialog-content h5 {
    margin-bottom: 1rem;
}

.dialog-actions {
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
    margin-top: 1.5rem;
}

