@namespace sv_d4f52afe12f64f4eab6541c86f46a356.Components.Pages.Settings
@using sv_d4f52afe12f64f4eab6541c86f46a356.Models

<div class="sessions-section">
    <h6>Active Sessions</h6>
    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions found.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession> Sessions { get; set; } = [];

    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<ActiveSession> OnRevokeRequested { get; set; }
}

@namespace sv_d4f52afe12f64f4eab6541c86f46a356.Components.Pages.Settings
@using sv_d4f52afe12f64f4eab6541c86f46a356.Models

<div class="password-panel">
    <button class="panel-toggle" @onclick="ToggleExpanded">
        <span>🔑 Change Password</span>
        <span class="toggle-icon">@(IsExpanded ? "▲" : "▼")</span>
    </button>

    @if (IsExpanded)
    {
        <div class="panel-body">
            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="HandleUpdatePassword" disabled="@_isSaving">
                @if (_isSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    private bool IsExpanded { get; set; }
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _message;
    private bool _isError;
    private bool _isSaving;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task HandleUpdatePassword()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _message = "Current password is required.";
            _isError = true;
            return;
        }

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "New password is required.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _isSaving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _message = "Password updated successfully.";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _isSaving = false;
        }
    }
}

