@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _isLoading = true;
    private bool _isSaving;
    private string? _statusMessage;
    private bool _isError;

    // Represents all available channels in the app
    private static readonly string[] _allChannels =
        ["general", "announcements", "engineering", "design", "marketing", "support"];

    protected override async Task OnInitializedAsync()
    {
        _isLoading = true;
        try
        {
            _prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = _prefs.EmailNotifications;
            _pushNotifications = _prefs.PushNotifications;
            _weeklyDigest = _prefs.WeeklyDigest;
            _mutedChannels = [.. _prefs.MutedChannels];
        }
        finally
        {
            _isLoading = false;
        }
    }

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _statusMessage = null;
        _isSaving = true;
        try
        {
            var updated = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                [.. _mutedChannels]);
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _statusMessage = "Notification preferences saved.";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save preferences: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _isSaving = false;
        }
    }
}

