@inject ISettingsService SettingsService

<section class="settings-section">
    <h4>Notifications</h4>

    @if (_isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (_prefs is not null)
    {
        @if (_statusMessage is not null)
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="toggle-group">
            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Email Notifications</div>
                    <div class="toggle-description">Receive notifications via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Push Notifications</div>
                    <div class="toggle-description">Receive push notifications in your browser</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Weekly Digest</div>
                    <div class="toggle-description">Get a weekly summary of activity</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        <div class="channels-section">
            <h6>Muted Channels</h6>
            <p class="text-muted">Select channels you want to mute.</p>
            <div class="channels-list">
                @foreach (var channel in _allChannels)
                {
                    var isMuted = _mutedChannels.Contains(channel);
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@isMuted"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            </div>
        </div>

        <div class="section-actions">
            <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_isSaving">
                @if (_isSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Preferences
            </button>
        </div>
    }
</section>

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _isLoading = true;
    private bool _isSaving;
    private string? _statusMessage;
    private bool _isError;

    // Represents all available channels in the app
    private static readonly string[] _allChannels =
        ["general", "announcements", "engineering", "design", "marketing", "support"];

    protected override async Task OnInitializedAsync()
    {
        _isLoading = true;
        try
        {
            _prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = _prefs.EmailNotifications;
            _pushNotifications = _prefs.PushNotifications;
            _weeklyDigest = _prefs.WeeklyDigest;
            _mutedChannels = [.. _prefs.MutedChannels];
        }
        finally
        {
            _isLoading = false;
        }
    }

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _statusMessage = null;
        _isSaving = true;
        try
        {
            var updated = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                [.. _mutedChannels]);
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _statusMessage = "Notification preferences saved.";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save preferences: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _isSaving = false;
        }
    }
}
