<section class="settings-section">
    <h4>Security</h4>

    @if (_isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (_settings is not null)
    {
        @if (_statusMessage is not null)
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <div class="two-factor-section">
            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Two-Factor Authentication</div>
                    <div class="toggle-description">
                        @if (_settings.TwoFactorEnabled)
                        {
                            <span class="badge bg-success me-1">Enabled</span>
                            <span>Your account has an extra layer of security.</span>
                        }
                        else
                        {
                            <span class="badge bg-warning text-dark me-1">Disabled</span>
                            <span>Add an extra layer of security to your account.</span>
                        }
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_settings.TwoFactorEnabled" disabled />
                </div>
            </div>

            @if (_settings.LastPasswordChange.HasValue)
            {
                <p class="text-muted mt-2">
                    Last password change: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <ActiveSessionsTable Sessions="_settings.Sessions.ToList()"
                             CurrentSessionId="@_settings.Sessions.FirstOrDefault()?.Id"
                             OnRevokeRequested="PromptRevokeSession" />

        <RevokeSessionDialog Session="_sessionToRevoke"
                             IsRevoking="_isRevoking"
                             OnConfirm="ConfirmRevoke"
                             OnCancel="CancelRevoke" />
    }
</section>

@code {
    private SecuritySettings? _settings;
    private bool _isLoading = true;
    private string? _statusMessage;
    private bool _isError;
    private ActiveSession? _sessionToRevoke;
    private bool _isRevoking;

    protected override async Task OnInitializedAsync()
    {
        await LoadSettings();
    }

    private async Task LoadSettings()
    {
        _isLoading = true;
        try
        {
            _settings = await SettingsService.GetSecuritySettingsAsync();
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task HandleChangePassword((string CurrentPassword, string NewPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.CurrentPassword, args.NewPassword);
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;

        _isRevoking = true;
        _statusMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _statusMessage = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _isError = false;
            _sessionToRevoke = null;
            await LoadSettings();
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to revoke session: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _isRevoking = false;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}
