@namespace sv_d4f52afe12f64f4eab6541c86f46a356.Components.Pages.Settings
@using sv_d4f52afe12f64f4eab6541c86f46a356.Models
@inject ISettingsService SettingsService

<section class="settings-section">
    <h4>Profile</h4>

    @if (_isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (_profile is not null)
    {
        @if (_statusMessage is not null)
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="profile-layout">
            <div class="avatar-area">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar preview" />
                    }
                    else
                    {
                        <span class="avatar-placeholder">👤</span>
                    }
                </div>
                <div class="avatar-url">
                    <label class="form-label">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>

            <div class="profile-fields">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
        </div>

        <div class="section-actions">
            <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_isSaving">
                @if (_isSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_isSaving">
                Discard Changes
            </button>
        </div>
    }
</section>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _isLoading = true;
    private bool _isSaving;
    private string? _statusMessage;
    private bool _isError;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
    }

    private async Task LoadProfile()
    {
        _isLoading = true;
        try
        {
            _profile = await SettingsService.GetProfileAsync();
            PopulateFields(_profile);
        }
        finally
        {
            _isLoading = false;
        }
    }

    private void PopulateFields(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveChanges()
    {
        _statusMessage = null;
        _isSaving = true;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _statusMessage = "Profile saved successfully.";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save profile: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _isSaving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_profile is not null)
        {
            PopulateFields(_profile);
            _statusMessage = null;
        }
    }
}

