.settings-section {
    padding: 0.5rem 0;
}

.settings-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.profile-layout {
    display: flex;
    gap: 2rem;
    margin-bottom: 1.5rem;
}

.avatar-area {
    flex-shrink: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.75rem;
}

.avatar-preview {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    border: 3px solid #dee2e6;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 3rem;
}

.avatar-url {
    width: 200px;
}

.profile-fields {
    flex: 1;
}

.section-actions {
    display: flex;
    gap: 0.5rem;
    padding-top: 0.5rem;
    border-top: 1px solid #dee2e6;
}

