toolArgs.file_text:
@namespace sv_d4f52afe12f64f4eab6541c86f46a356.Components.Pages.Settings
@using sv_d4f52afe12f64f4eab6541c86f46a356.Models
@inject ISettingsService SettingsService

<section class="settings-section">
    <h4>Appearance</h4>

    @if (_isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        @if (_statusMessage is not null)
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="appearance-layout">
            <div class="appearance-controls">
                <div class="control-group">
                    <h6>Theme</h6>
                    <div class="radio-group">
                        @foreach (var theme in _themes)
                        {
                            <label class="radio-card @(_theme == theme.Value ? "selected" : "")">
                                <input type="radio" name="theme" value="@theme.Value"
                                       checked="@(_theme == theme.Value)"
                                       @onchange="() => _theme = theme.Value" />
                                <span class="radio-icon">@theme.Icon</span>
                                <span>@theme.Label</span>
                            </label>
                        }
                    </div>
                </div>

                <div class="control-group">
                    <h6>Font Size</h6>
                    <div class="radio-group">
                        @foreach (var size in _fontSizes)
                        {
                            <label class="radio-card @(_fontSize == size.Value ? "selected" : "")">
                                <input type="radio" name="fontSize" value="@size.Value"
                                       checked="@(_fontSize == size.Value)"
                                       @onchange="() => _fontSize = size.Value" />
                                <span style="font-size: @size.Preview">Aa</span>
                                <span>@size.Label</span>
                            </label>
                        }
                    </div>
                </div>

                <div class="control-group">
                    <h6>Language</h6>
                    <select class="form-select" @bind="_language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>

                <div class="control-group">
                    <div class="toggle-row">
                        <div>
                            <div class="toggle-label">Compact Mode</div>
                            <div class="toggle-description">Reduce spacing and padding for a denser layout</div>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_compactMode"
                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        </div>
                    </div>
                </div>
            </div>

            <div class="preview-area">
                <h6>Live Preview</h6>
                <div class="preview-card @GetPreviewThemeClass()" style="font-size: @GetPreviewFontSize(); @GetPreviewPadding()">
                    <div class="preview-header">
                        <strong>Sample Card</strong>
                    </div>
                    <p>This is how your content will look with the selected settings.</p>
                    <div class="preview-actions">
                        <span class="preview-btn primary">Primary</span>
                        <span class="preview-btn secondary">Secondary</span>
                    </div>
                </div>
            </div>
        </div>

        <div class="section-actions">
            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_isSaving">
                @if (_isSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>
    }
</section>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _isLoading = true;
    private bool _isSaving;
    private string? _statusMessage;
    private bool _isError;

    private record ThemeOption(string Value, string Label, string Icon);
    private record FontSizeOption(string Value, string Label, string Preview);

    private static readonly ThemeOption[] _themes =
    [
        new("Light", "Light", "☀️"),
        new("Dark", "Dark", "🌙"),
        new("System", "System", "💻"),
    ];

    private static readonly FontSizeOption[] _fontSizes =
    [
        new("Small", "Small", "0.8rem"),
        new("Medium", "Medium", "1rem"),
        new("Large", "Large", "1.2rem"),
    ];

    protected override async Task OnInitializedAsync()
    {
        _isLoading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private string GetPreviewThemeClass() => _theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light",
    };

    private string GetPreviewFontSize() => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem",
    };

    private string GetPreviewPadding() => _compactMode
        ? "padding: 0.5rem;"
        : "padding: 1.25rem;";

    private async Task SaveAppearance()
    {
        _statusMessage = null;
        _isSaving = true;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(updated);
            _statusMessage = "Appearance settings saved.";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save appearance: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _isSaving = false;
        }
    }
}

