+                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
+                        </div>
+                    </div>
+                </div>
+            </div>
+
+            <div class="preview-area">
+                <h6>Live Preview</h6>
+                <div class="preview-card @GetPreviewThemeClass()" style="font-size: @GetPreviewFontSize(); @GetPreviewPadding()">
+                    <div class="preview-header">
+                        <strong>Sample Card</strong>
+                    </div>
+                    <p>This is how your content will look with the selected settings.</p>
+                    <div class="preview-actions">
+                        <span class="preview-btn primary">Primary</span>
+                        <span class="preview-btn secondary">Secondary</span>
+                    </div>
+                </div>
+            </div>
+        </div>
+
+        <div class="section-actions">
+            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_isSaving">
+                @if (_isSaving)
+                {
+                    <span class="spinner-border spinner-border-sm me-1"></span>
+                }
+                Save
+            </button>
+        </div>
+    }
+</section>
+
+@code {
+    private string _theme = "Light";
+    private string _fontSize = "Medium";
+    private string _language = "en";
+    private bool _compactMode;
+    private bool _isLoading = true;
+    private bool _isSaving;
+    private string? _statusMessage;
+    private bool _isError;
+
+    private record ThemeOption(string Value, string Label, string Icon);
+    private record FontSizeOption(string Value, string Label, string Preview);
+
+    private static readonly ThemeOption[] _themes =
+    [
+        new("Light", "Light", "☀️"),
+        new("Dark", "Dark", "🌙"),
+        new("System", "System", "💻"),
+    ];
+
+    private static readonly FontSizeOption[] _fontSizes =
+    [
+        new("Small", "Small", "0.8rem"),
+        new("Medium", "Medium", "1rem"),
+        new("Large", "Large", "1.2rem"),
+    ];
+
+    protected override async Task OnInitializedAsync()
+    {
+        _isLoading = true;
+        try
+        {
+            var settings = await SettingsService.GetAppearanceAsync();
+            _theme = settings.Theme;
+            _fontSize = settings.FontSize;
+            _language = settings.Language;
+            _compactMode = settings.CompactMode;
+        }
+        finally
+        {
+            _isLoading = false;
+        }
+    }
+
+    private string GetPreviewThemeClass() => _theme switch
+    {
+        "Dark" => "preview-dark",
+        _ => "preview-light",
+    };
+
+    private string GetPreviewFontSize() => _fontSize switch
+    {
+        "Small" => "0.85rem",
+        "Large" => "1.15rem",
+        _ => "1rem",
+    };
+
+    private string GetPreviewPadding() => _compactMode
+        ? "padding: 0.5rem;"
+        : "padding: 1.25rem;";
+
+    private async Task SaveAppearance()
+    {
+        _statusMessage = null;
+        _isSaving = true;
+        try
+        {
+            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
+            await SettingsService.SaveAppearanceAsync(updated);
+            _statusMessage = "Appearance settings saved.";
+            _isError = false;
+        }
+        catch (Exception ex)
+        {
+            _statusMessage = $"Failed to save appearance: {ex.Message}";
+            _isError = true;
+        }
+        finally
+        {
+            _isSaving = false;
+        }
+    }
+}
+

toolArgs.file_text:
.settings-section {
    padding: 0.5rem 0;
}

.settings-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.appearance-layout {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 2rem;
    margin-bottom: 1.5rem;
}

.control-group {
    margin-bottom: 1.5rem;
}

.control-group h6 {
    margin-bottom: 0.75rem;
    font-weight: 600;
}

.radio-group {
    display: flex;
    gap: 0.5rem;
}

.radio-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.25rem;
    padding: 0.75rem 1rem;
    border: 2px solid #dee2e6;
    border-radius: 0.5rem;
    cursor: pointer;
    transition: all 0.15s ease;
    font-size: 0.9rem;
}

.radio-card input[type="radio"] {
    display: none;
}

.radio-card:hover {
    border-color: #adb5bd;
}

.radio-card.selected {
    border-color: #0d6efd;
    background: #e7f1ff;
}

.radio-icon {
    font-size: 1.25rem;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.toggle-label {
    font-weight: 500;
}

.toggle-description {
    font-size: 0.85rem;
    color: #6c757d;
}

.preview-area h6 {
    margin-bottom: 0.75rem;
    font-weight: 600;
}

.preview-card {
    border-radius: 0.75rem;
    border: 1px solid #dee2e6;
    transition: all 0.2s ease;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-header {
    margin-bottom: 0.75rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid currentColor;
    opacity: 0.3;
}

.preview-header strong {
    opacity: 1;
}

.preview-card p {
    margin-bottom: 1rem;
    opacity: 0.8;
}

.preview-actions {
    display: flex;
    gap: 0.5rem;
}

.preview-btn {
    padding: 0.35rem 0.75rem;
    border-radius: 0.375rem;
    font-size: 0.85em;
}

.preview-btn.primary {
    background: #0d6efd;
    color: #fff;
}

.preview-dark .preview-btn.primary {
    background: #89b4fa;
    color: #1e1e2e;
}

.preview-btn.secondary {
    background: #e9ecef;
    color: #495057;
}

.preview-dark .preview-btn.secondary {
    background: #45475a;
    color: #cdd6f4;
}

.section-actions {
    display: flex;
    gap: 0.5rem;
    padding-top: 0.5rem;
    border-top: 1px solid #dee2e6;
}

